class Solution {
    public String minimizeStringValue(String s) {
        int[] freq = new int[26];
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c != '?') {
                res.append(c);
                int idx = c - 'a';
                freq[idx]++;
            } else {
                char best = 'a';
                int minFreq = Integer.MAX_VALUE;
                for (char ch = 'a'; ch <= 'z'; ch++) {
                    int idx = ch - 'a';
                    if (freq[idx] < minFreq) {
                        minFreq = freq[idx];
                        best = ch;
                    }
                }
                res.append(best);
                int bestIdx = best - 'a';
                freq[bestIdx]++;
            }
        }
        return res.toString();
    }
}

